/// </summary>
public class BackgroundProcessor : IDisposable
{
    private readonly CancellationTokenSource _cts = new();
    private Task? _workerTask;

    public void Start()
    {
        _workerTask = Task.Run(() => ProcessLoop(_cts.Token));
    }

    private async Task ProcessLoop(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                // CRITICAL: pass the token into any blocking/async call.
                // If GetNextItem() is synchronous and can't accept a token,
                // see the "Legacy Blocking Adapter" section below.
                var item = await GetNextItemAsync(ct);
                await ProcessItemAsync(item, ct);
            }
            catch (OperationCanceledException) when (ct.IsCancellationRequested)
            {
                // Normal shutdown — replaces the old ThreadAbortException handler.
                // Roll back any partial work, then exit cleanly.
                RollbackCurrentTransaction();
                break;
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

